const items = $input.all();
const results = [];

for (const item of items) {
  const prompt = item.json.PROMPT;
  const imagesRaw = item.json.IMAGES;

  // Splitta le URL per virgola e pulisce gli spazi
  const imagesArray = imagesRaw
    .split(',')
    .map(url => url.trim())
    .filter(url => url.length > 0);

  results.push({
    json: {
      PROMPT: prompt,
      IMAGES: JSON.stringify(imagesArray),
    }
  });
}

return results;

const text = $input.first().json.text;

const cleaned = text.trim();

const parsed = JSON.parse(cleaned);

return parsed.map(item => ({ json: item }));

const items = $input.all();
const results = [];

for (const item of items) {
  const resultJson = JSON.parse(item.json.data.resultJson);
  const imageUrl = resultJson.resultUrls[0];

  results.push({
    json: {
      imageUrl: imageUrl,
    }
  });
}

return results;
